1. #!/usr/bin/env node
2. "use strict";
3. 
4. /**
5.  * Simple Gemini image CLI wrapper (no dependencies).
6.  *
7.  * Usage:
8.  *   nanobanana --prompt "A banana astronaut in space"
9.  *   nanobanana -p "Stylize this" -i .\ref1.png -i .\ref2.jpg --resolution 512
10.  *   nanobanana --prompt "Forecast infographic" --google-search
11.  */
12. 
13. const fs = require("node:fs");
14. const path = require("node:path");
15. 
16. const DEFAULT_MODEL = process.env.NANOBANANA_MODEL || "gemini-3.1-flash-image-preview";
17. const DEFAULT_THINKING = "high";
18. const DEFAULT_ASPECT_RATIO = "Auto";
19. const DEFAULT_RESOLUTION = "1K";
20. const DEFAULT_OUTPUT_MODE = "images";
21. const DEFAULT_OUTPUT_DIR = "nanobanana-output";
22. const MAX_REFERENCE_IMAGES = 14;
23. const HELP_FLAGS = new Set(["-h", "--help"]);
24. 
25. function printHelp() {
26.   console.log(`Nano Banana Gemini Image CLI
27. 
28. Usage:
29.   nanobanana [options] --prompt "your prompt"
30.   nanobanana [options] "your prompt"
31.   npx @willh/nanobanana-cli [options] --prompt "your prompt"
32. 
33. Options:
34.   -p, --prompt <text>         Prompt text
35.   -i, --image <path>          Reference image path (repeatable, max 14)
36.       --images <p1,p2,...>    Comma-separated image paths (max 14 total)
37.       --model <name>          Model (default: NANOBANANA_MODEL or gemini-3.1-flash-image-preview)
38.       --thinking <level>      minimal | low | medium | high (default: high)
39.       --aspect-ratio <ratio>  e.g. 1:1, 16:9, 5:4, Auto (default: Auto)
40.       --resolution <size>     512 | 512px | 1K | 2K | 4K (default: 1K)
41.       --output-mode <mode>    images | both (default: images)
42.       --google-search         Enable Google Search grounding tool
43.       --output-dir <dir>      Save directory (default: nanobanana-output, or inferred from prompt)
44.       --api-key <key>         Gemini API key (default: NANOBANANA_GEMINI_API_KEY, fallback: GEMINI_API_KEY)
45.       --name-prefix <prefix>  Output file prefix (default: nanobanana)
46.   -h, --help                  Show help
47. `);
48. }
49. 
50. function getValue(args, index, optionName) {
51.   const value = args[index + 1];
52.   if (!value || value.startsWith("-")) {
53.     throw new Error(`Missing value for ${optionName}.`);
54.   }
55.   return value;
56. }
57. 
58. function parseArgs(argv) {
59.   const args = argv.slice(2);
60.   const result = {
61.     prompt: "",
62.     images: [],
63.     model: DEFAULT_MODEL,
64.     thinking: DEFAULT_THINKING,
65.     aspectRatio: DEFAULT_ASPECT_RATIO,
66.     resolution: DEFAULT_RESOLUTION,
67.     outputMode: DEFAULT_OUTPUT_MODE,
68.     googleSearch: false,
69.     outputDir: "",
70.     apiKey: process.env.NANOBANANA_GEMINI_API_KEY || process.env.GEMINI_API_KEY || "",
71.     namePrefix: "nanobanana",
72.   };
73.   const promptParts = [];
74. 
75.   for (let i = 0; i < args.length; i += 1) {
76.     const arg = args[i];
77.     if (HELP_FLAGS.has(arg)) {
78.       result.help = true;
79.       continue;
80.     }
81. 
82.     if (arg === "--") {
83.       promptParts.push(...args.slice(i + 1));
84.       break;
85.     }
86. 
87.     switch (arg) {
88.       case "-p":
89.       case "--prompt":
90.         result.prompt = getValue(args, i, arg);
91.         i += 1;
92.         break;
93.       case "-i":
94.       case "--image":
95.         result.images.push(getValue(args, i, arg));
96.         i += 1;
97.         break;
98.       case "--images":
99.         result.images.push(
100.           ...getValue(args, i, arg)
101.             .split(",")
102.             .map((v) => v.trim())
103.             .filter(Boolean),
104.         );
105.         i += 1;
106.         break;
107.       case "--model":
108.         result.model = getValue(args, i, arg);
109.         i += 1;
110.         break;
111.       case "--thinking":
112.         result.thinking = getValue(args, i, arg);
113.         i += 1;
114.         break;
115.       case "--aspect-ratio":
116.         result.aspectRatio = getValue(args, i, arg);
117.         i += 1;
118.         break;
119.       case "--resolution":
120.         result.resolution = getValue(args, i, arg);
121.         i += 1;
122.         break;
123.       case "--output-mode":
124.         result.outputMode = getValue(args, i, arg);
125.         i += 1;
